/**
 * Webhook notification handler for order events.
 *
 * Subscribes to order lifecycle events via EventBus and dispatches
 * HTTP webhook callbacks to registered URLs. Follows the same pattern
 * as EmailNotificationHandler for consistency.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType } from '../events/event-types.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  createdAt: Date;
}

export interface WebhookDelivery {
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  timestamp: Date;
}

export interface WebhookPayload {
  event: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

/**
 * Function type for the HTTP sender, allowing injection for testing.
 * In production, this would call fetch(). In tests, a stub is provided.
 */
export type WebhookSender = (url: string, payload: WebhookPayload) => Promise<boolean>;

const defaultSender: WebhookSender = async (_url, _payload) => {
  // Default no-op sender for demo purposes.
  // In production, this would be: fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) })
  return true;
};

let nextWebhookId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextWebhookId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private sender: WebhookSender;

  constructor(private eventBus: EventBus, sender?: WebhookSender) {
    this.sender = sender ?? defaultSender;
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Processing webhooks for order:created ${event.order.id}`);

    const payload: WebhookPayload = {
      event: 'order:created',
      timestamp: event.timestamp.toISOString(),
      data: {
        orderId: event.order.id,
        userId: event.order.userId,
        items: event.order.items.map((item) => ({
          productId: item.productId,
          name: item.name,
          quantity: item.quantity,
          unitPrice: item.unitPrice,
        })),
        total: event.order.total,
        status: event.order.status,
      },
    };

    await this.dispatchWebhooks('order:created', payload);
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Processing webhooks for order:status-changed ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const payload: WebhookPayload = {
      event: 'order:status-changed',
      timestamp: event.timestamp.toISOString(),
      data: {
        orderId: event.order.id,
        userId: event.order.userId,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    };

    await this.dispatchWebhooks('order:status-changed', payload);
  }

  private async dispatchWebhooks(eventType: EventType, payload: WebhookPayload): Promise<void> {
    const matching = this.registrations.filter((r) => r.eventType === eventType);

    for (const registration of matching) {
      let success = false;
      try {
        success = await this.sender(registration.url, payload);
      } catch {
        success = false;
      }

      const delivery: WebhookDelivery = {
        webhookId: registration.id,
        url: registration.url,
        eventType,
        payload,
        success,
        timestamp: new Date(),
      };

      this.deliveries.push(delivery);
      this.logger.info(
        `Webhook ${registration.id} dispatched to ${registration.url}: ${success ? 'success' : 'failed'}`,
      );
    }
  }

  /**
   * Register a webhook URL for a specific event type.
   * Returns the registration ID.
   */
  registerWebhook(url: string, eventType: EventType): string {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      createdAt: new Date(),
    };

    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
    return registration.id;
  }

  /**
   * Unregister a webhook by its ID.
   * Returns true if found and removed.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Get all webhook registrations.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get delivery records for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clearAll(): void {
    this.registrations = [];
    this.deliveries = [];
  }
}

