import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounter,
} from '../../src/notifications/webhook-handler.js';
import type { WebhookPayload, WebhookSender } from '../../src/notifications/webhook-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookHandler;
  let mockSender: WebhookSender;
  let sentRequests: { url: string; payload: WebhookPayload }[];

  beforeEach(() => {
    eventBus = new EventBus();
    sentRequests = [];
    resetWebhookIdCounter();

    mockSender = async (url, payload) => {
      sentRequests.push({ url, payload });
      return true;
    };

    handler = new WebhookHandler(eventBus, mockSender);
  });

  const makeOrderCreatedEvent = (): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2024-01-01T00:00:00Z'),
  });

  const makeStatusChangedEvent = (
    previousStatus: string,
    newStatus: string,
  ): OrderStatusChangedEvent => ({
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: newStatus as any,
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus,
    newStatus,
    timestamp: new Date('2024-01-01T00:00:00Z'),
  });

  describe('webhook registration', () => {
    it('should register a webhook and return an ID', () => {
      const id = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(id).toBe('webhook-0001');
      expect(handler.getRegistrations()).toHaveLength(1);
      expect(handler.getRegistrations()[0]?.url).toBe('https://example.com/hook');
      expect(handler.getRegistrations()[0]?.eventType).toBe('order:created');
    });

    it('should generate sequential IDs', () => {
      const id1 = handler.registerWebhook('https://a.com/hook', 'order:created');
      const id2 = handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(id1).toBe('webhook-0001');
      expect(id2).toBe('webhook-0002');
    });

    it('should allow multiple webhooks for the same event', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(1);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const id = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(handler.unregisterWebhook(id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  describe('order:created webhook dispatch', () => {
    it('should dispatch to registered webhooks on order created', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sentRequests).toHaveLength(1);
      expect(sentRequests[0]?.url).toBe('https://example.com/hook');
      expect(sentRequests[0]?.payload.event).toBe('order:created');
      expect(sentRequests[0]?.payload.data.orderId).toBe('order-1');
      expect(sentRequests[0]?.payload.data.total).toBe(20);
      expect(sentRequests[0]?.payload.data.status).toBe('pending');
    });

    it('should include item details in order:created payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const items = sentRequests[0]?.payload.data.items as any[];
      expect(items).toHaveLength(1);
      expect(items[0].name).toBe('Widget');
      expect(items[0].quantity).toBe(2);
      expect(items[0].unitPrice).toBe(10);
    });

    it('should include ISO timestamp in payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sentRequests[0]?.payload.timestamp).toBe('2024-01-01T00:00:00.000Z');
    });

    it('should dispatch to multiple webhooks for same event', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sentRequests).toHaveLength(2);
      expect(sentRequests[0]?.url).toBe('https://a.com/hook');
      expect(sentRequests[1]?.url).toBe('https://b.com/hook');
    });

    it('should not dispatch to webhooks registered for other events', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sentRequests).toHaveLength(0);
    });
  });

  describe('order:status-changed webhook dispatch', () => {
    it('should dispatch on status change', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      expect(sentRequests).toHaveLength(1);
      expect(sentRequests[0]?.payload.event).toBe('order:status-changed');
      expect(sentRequests[0]?.payload.data.previousStatus).toBe('pending');
      expect(sentRequests[0]?.payload.data.newStatus).toBe('confirmed');
      expect(sentRequests[0]?.payload.data.orderId).toBe('order-1');
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      const id = handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.webhookId).toBe(id);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.eventType).toBe('order:created');
    });

    it('should record failed deliveries', async () => {
      const failingSender: WebhookSender = async () => false;
      const failHandler = new WebhookHandler(eventBus, failingSender);
      failHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = failHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
    });

    it('should handle sender throwing an error as a failed delivery', async () => {
      const throwingSender: WebhookSender = async () => {
        throw new Error('Network error');
      };
      const errorHandler = new WebhookHandler(eventBus, throwingSender);
      errorHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = errorHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
    });

    it('should filter deliveries by webhook ID', async () => {
      const id1 = handler.registerWebhook('https://a.com/hook', 'order:created');
      const id2 = handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForWebhook(id1)).toHaveLength(1);
      expect(handler.getDeliveriesForWebhook(id2)).toHaveLength(1);
    });

    it('should count deliveries', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      expect(handler.getDeliveryCount()).toBe(0);

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveryCount()).toBe(2);
    });

    it('should accumulate deliveries across events', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      handler.registerWebhook('https://example.com/hook2', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      expect(handler.getDeliveryCount()).toBe(2);
    });
  });

  describe('clearAll', () => {
    it('should clear registrations and deliveries', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clearAll();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });

  describe('no registered webhooks', () => {
    it('should not dispatch when no webhooks are registered', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      expect(sentRequests).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });
});

